	DB_TXN_PREPARED *p;
	Pthread_mutex_lock(&dbenv->prepared_txn_lk);
	if ((p = hash_find(dbenv->prepared_txn_hash, &dist_txnid)) != NULL) {
		hash_del(dbenv->prepared_txn_hash, p);
		hash_del(dbenv->prepared_utxnid_hash, p);
		__free_prepared_children(dbenv, p);
