	Pthread_mutex_unlock(&dbenv->prepared_txn_lk);
	if (p == NULL) {
		logmsg(LOGMSG_INFO, "%s unable to locate txnid %s\n", __func__, dist_txnid);
		return -1;
	}

	return __discard(dbenv, p);
}

